import { renderHook, act, waitFor } from '@testing-library/react';
import { jest, describe, beforeEach, test, expect } from '@jest/globals';
import { useForoGrid } from '@/app/GerAdv_TS/Foro/Hooks/hookForoGrid';
import { IForo } from '@/app/GerAdv_TS/Foro/Interfaces/interface.Foro';

// Sample minimal foro item for tests
const sampleForo = (overrides?: Partial<IForo>): IForo => ({
  id: 1,
 email: 'menphis@menphis.com.br',
nome: 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA',
unico: false,
cidade: 0,
site: 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA',
endereco: 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA',
bairro: 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA',
fone: '',
fax: '',
cep: 'AAAAAAAA',
obs: '',
unicoconfirmado: true,
web: 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA',

  ...overrides,
} as IForo);

describe('useForoGrid', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    // Clear localStorage to avoid persisted column order
    try {
      localStorage.clear();
    } catch (e) {}
  });

  test('inicializa com dados processados e paginação', () => {
    const data = [sampleForo({ id: 1 }), sampleForo({ id: 2 })];
    const onRowClick = jest.fn();
    const onDeleteClick = jest.fn();
    const setSelectedId = jest.fn();

    const { result } = renderHook(() =>
      useForoGrid({
        data,
        onRowClick,
        onDeleteClick,
        setSelectedId,
        initialTake: 1,
      })
    );

    // filteredData should equal provided data (no filters applied)
    expect(result.current.filteredData.length).toBe(2);
    // paginatedData should respect initialTake=1
    expect(result.current.paginatedData.length).toBe(1);
    expect(result.current.page.take).toBe(1);
    // gridConfig should include handlers
    expect(typeof result.current.gridConfig.onRowClick).toBe('function');
  });

  test('handleRowClick chama onRowClick com item correto', () => {
    const data = [sampleForo({ id: 5 })];
    const onRowClick = jest.fn();
    const onDeleteClick = jest.fn();
    const setSelectedId = jest.fn();

    const { result } = renderHook(() =>
      useForoGrid({ data, onRowClick, onDeleteClick, setSelectedId })
    );

    act(() => {
      result.current.handleRowClick({ dataItem: data[0] });
    });

    expect(onRowClick).toHaveBeenCalledWith(data[0]);
  });

  test('resetColumnsOrder restaura ordem padrão e limpa localStorage', () => {
    const data = [sampleForo()];
    const onRowClick = jest.fn();
    const onDeleteClick = jest.fn();
    const setSelectedId = jest.fn();

    const { result } = renderHook(() =>
      useForoGrid({ data, onRowClick, onDeleteClick, setSelectedId })
    );

    // Simula mudança de ordem salvo no localStorage
    try {
      localStorage.setItem(btoa('foro-columns-order'), JSON.stringify(['nome','data']));
    } catch(e) {}

    act(() => {
      result.current.resetColumnsOrder();
    });

    expect(result.current.columnsOrder).toBeInstanceOf(Array);
    // localStorage key deve ter sido removida
    try {
      const v = localStorage.getItem(btoa('foro-columns-order'));
      expect(v).toBeNull();
    } catch (e) {}
  });

  test('filterLogic filtra por nome', async () => {
    const matching = sampleForo({ nome: 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA' });
    const notMatching = sampleForo({ nome: 'Outro' });
    const data = [matching, notMatching];
    const onRowClick = jest.fn();
    const onDeleteClick = jest.fn();
    const setSelectedId = jest.fn();

    const { result } = renderHook(() =>
      useForoGrid({ data, onRowClick, onDeleteClick, setSelectedId })
    );

    // Aplica filtro via handleFilterChange
    act(() => {
      result.current.handleFilterChange({ field: 'nome', value: 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA' } as any);
    });

    // Espera que filteredData contenha apenas o item correspondente
    await waitFor(() => {
      expect(result.current.filteredData.some((d) => d.nome === 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA')).toBe(true);
    });
  });
});
